import users from ''

function UserList(){
    users.map((user) =>{
        return(
            <article>
                <h3>{user.first_name}</h3>
                <p>User Group: {user.user_group}</p>
                <p>ID: {user.id}</p>
            </article>
        );
    });
}

export default UserList;
